Here's a simple C login program that checks a username and password:

```c
#include <stdio.h>
#include <string.h>

#define MAX_LEN 50
#define CORRECT_USERNAME "admin"
#define CORRECT_PASSWORD "password123"

int main() {
    char username[MAX_LEN];
    char password[MAX_LEN];
    int attempts = 0;
    int max_attempts = 3;

    printf("=== Login Page ===\n");

    while (attempts < max_attempts) {
        printf("\nUsername: ");
        if (fgets(username, sizeof(username), stdin) == NULL) {
            printf("Error reading input.\n");
            return 1;
        }
        // Remove trailing newline
        username[strcspn(username, "\n")] = '\0';

        printf("Password: ");
        if (fgets(password, sizeof(password), stdin) == NULL) {
            printf("Error reading input.\n");
            return 1;
        }
        // Remove trailing newline
        password[strcspn(password, "\n")] = '\0';

        // Check credentials
        if (strcmp(username, CORRECT_USERNAME) == 0 &&
            strcmp(password, CORRECT_PASSWORD) == 0) {
            printf("\n✓ Login successful! Welcome, %s!\n", username);
            return 0;
        } else {
            attempts++;
            int remaining = max_attempts - attempts;
            if (remaining > 0) {
                printf("✗ Invalid username or password. %d attempt(s) remaining.\n", remaining);
            } else {
                printf("✗ Too many failed attempts. Access denied.\n");
            }
        }
    }

    return 1;
}
```

### How it works:
- **Credentials** are defined as constants at the top (`CORRECT_USERNAME` and `CORRECT_PASSWORD`) — easy to change.
- **`fgets`** is used instead of `scanf` or `gets` to safely read input and prevent buffer overflows.
- **`strcspn`** strips the trailing newline that `fgets` captures.
- **`strcmp`** compares the entered credentials against the stored ones.
- **3 login attempts** are allowed before access is denied.

### To compile and run:
```bash
gcc -o login login.c
./login
```

### Example output:
```
=== Login Page ===

Username: admin
Password: password123

✓ Login successful! Welcome, admin!
```

> **Note:** For any real application, **never store passwords in plaintext**. Use a hashing library like `libsodium` or `OpenSSL` with a proper hashing algorithm (e.g., bcrypt or Argon2) to store and verify passwords securely.

